#include "mad/runtime/evaluator.hpp"
#include <algorithm>
#include <cmath>
namespace mad::runtime {
void Evaluator::Reset(){ m_metrics={}; m_previousSpeed=0.0; m_previousTime=0.0; m_hasPrevious=false; }
FrameMetrics Evaluator::Update(const mad::simulation::WorldSnapshot& snapshot, const std::vector<mad::prediction::PredictedObject>& predictions, const mad::map::LaneMap& lane_map){ FrameMetrics frame; const int lane_id=lane_map.ClosestLane(snapshot.ego.y); frame.min_ttc = m_interactionPredictor.MinTimeToCollisionInLane(snapshot.ego, predictions, lane_id); frame.lane_error = std::abs(snapshot.ego.y - lane_map.LaneCenterY(lane_id)); double headway_distance=1.0e9; for(const auto& p:predictions){ if(p.lane_id!=lane_id || p.current_x <= snapshot.ego.x) continue; headway_distance=std::min(headway_distance, p.current_x - snapshot.ego.x);} frame.headway = snapshot.ego.speed > 0.5 ? headway_distance / snapshot.ego.speed : 1.0e9; if(m_hasPrevious){ const double dt=std::max(1.0e-3, snapshot.sim_time-m_previousTime); frame.longitudinal_accel=(snapshot.ego.speed - m_previousSpeed)/dt; } m_previousSpeed=snapshot.ego.speed; m_previousTime=snapshot.sim_time; m_hasPrevious=true; m_metrics.samples += 1; m_metrics.avg_speed += snapshot.ego.speed; m_metrics.avg_lane_error += frame.lane_error; if(frame.headway < 1.0e8) m_metrics.avg_headway += frame.headway; m_metrics.min_ttc = std::min(m_metrics.min_ttc, frame.min_ttc); m_metrics.max_abs_accel = std::max(m_metrics.max_abs_accel, std::abs(frame.longitudinal_accel)); return frame; }
AggregateMetrics Evaluator::Summary() const { AggregateMetrics out=m_metrics; if(out.samples>0){ out.avg_speed/=static_cast<double>(out.samples); out.avg_lane_error/=static_cast<double>(out.samples); out.avg_headway/=static_cast<double>(out.samples);} return out; }
}
